  it('should use the provided encoding when options is passed as a string', () => {
    const tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), 'jsonfile-test-'))
    const tmpFile = path.join(tmpDir, 'test.json')

    try {
      const testData = { hello: 'world', num: 123 }
      fs.writeFileSync(tmpFile, JSON.stringify(testData), 'utf8')

      // Pass encoding as a string - original code converts to { encoding: 'utf8' }
      // mutated code converts to {} losing the encoding
      // With no encoding, fs.readFileSync returns a Buffer
      // stripBom on a Buffer returns a Buffer
      // JSON.parse(Buffer) - this actually works in Node.js
      // BUT: with options = {}, options.reviver is undefined which is fine
      // The real test: does it return the correct parsed object?
      const result = jsonfile.readFileSync(tmpFile, 'utf8')

      expect(result).not.toBeNull()
      expect(typeof result).toBe('object')
      expect(result).toEqual(testData)
