    const tmpFile = path.join(tmpDir, 'test.json')

    try {
      const testData = { x: 1 }
      // Write file in utf16le encoding
      fs.writeFileSync(tmpFile, JSON.stringify(testData), 'utf16le')

      // Reading with 'utf16le' encoding should decode correctly and parse JSON
      // Without encoding (mutated), Buffer.toString() uses utf8 which will garble utf16le content
      const result = jsonfile.readFileSync(tmpFile, 'utf16le')

      expect(result).toEqual(testData)
    } finally {
      try { fs.unlinkSync(tmpFile) } catch {}
      try { fs.rmdirSync(tmpDir) } catch {}
    }
  })
})
```

This should work! A UTF-16LE encoded file read without encoding (as Buffer, then toString() which defaults to UTF-8) would produce garbled text that fails JSON parsing. With the correct encoding, it decodes properly.

